def prod_signs(arr):
    if not arr:
        return None

    magnitude_sum = 0
    sign_product = 1

    for num in arr:
        magnitude_sum += abs(num)
        if num == 0:
            sign_product = 0
        elif num < 0:
            sign_product *= -1

    return magnitude_sum * sign_product

import re

def valid_date(date):
    # Regular expression to match the date format mm-dd-yyyy
    pattern = r'^\d{2}-\d{2}-\d{4}$'

    # Check if the date matches the pattern
    if not re.match(pattern, date):
        return False

    # Extract month, day, and year from the date string
    month, day, year = map(int, date.split('-'))

    # Check if the month is between 1 and 12
    if month < 1 or month > 12:
        return False

    # Check if the day is between 1 and 31 based on the month
    if month in [1, 3, 5, 7, 8, 10, 12] and day < 1 or day > 31:
        return False
    elif month in [4, 6, 9, 11] and day < 1 or day > 30:
        return False
    elif month == 2 and (day < 1 or day > 29):
        return False

    return True

def tri(n):
    result = []
    for i in range(n + 1):
        if i == 0:
            result.append(1)
        elif i == 1:
            result.append(3)
        elif i % 2 == 0:
            result.append(1 + i // 2)
        else:
            result.append(result[i - 1] + result[i - 2] + (1 + (i + 1) // 2))
    return result

