def sum_squares(lst):
    total = 0
    for i, x in enumerate(lst):
        if i % 3 == 0:
            total += x ** 2
        elif i % 4 == 0:
            total += x ** 3
        else:
            total += x
    return total

def fix_spaces(text):
    result = []
    i = 0
    while i < len(text):
        if text[i] == " ":
            j = i
            while j < len(text) and text[j] == " ":
                j += 1
            count = j - i
            result.append("-" if count > 2 else "_" * count)
            i = j
        else:
            result.append(text[i])
            i += 1
    return "".join(result)

